
.contactum_state_box {
  border-radius: 8px;
  display: block;
  padding: 32px;
  text-align: center;
}
.contactum_icon_btn {
  align-items: center;
  background-color: #1a7efb;
  border-radius: 50%;
  color: #fff;
  display: flex;
  font-size: 28px;
  height: 58px;
  justify-content: center;
  text-align: center;
  width: 58px;
}
.contactum_icon_btn.success {
  background-color: #00b27f;
  color: #fff;
}
label {
  align-items: center;
  color: #1e1f21 !important;
  display: flex;
  font-size: 15px;
  font-weight: 500;
}


